// Solution:
// 1. Split the grid template areas into columns
// 2. Split each column into column names
// 3. Calculate the column width based on the grid template area
// 4. Return the column widths
function calculateColumnWidths(gridTemplateAreas) {
	const columns = gridTemplateAreas.split('] [');
	const columnWidths = {};
	for (const column of columns) {
		const columnNames = column.split(' ');
		let previousWidth = 0;
		for (const columnName of columnNames) {
			columnWidths[columnName] = previousWidth;
			previousWidth += columnName.length;
		}
	}
	return columnWidths;
}

